+        /// <summary>
+        /// Albums added or structurally changed since the given cursor that the requesting user can access.
+        /// </summary>
+        /// <param name="requestedBy"></param>
+        /// <param name="lastModified">Keyset cursor — exclusive lower bound on PhotoAlbums.LastModified</param>
+        /// <param name="lastAlbumId">Tie-break cursor — PhotoAlbumID component of the compound keyset</param>
+        /// <param name="limit">Maximum rows to return; 0 is treated as int.MaxValue</param>
+        /// <returns>Will not return null</returns>
+        public List<PhotoAlbumForMobile> GetAddedAlbumsForMobile(IRequestedBy requestedBy, DateTimeOffset lastModified, int lastAlbumId, int limit)
+        {
+            // Exceptions are handled by the caller
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                // Exceptions are handled by the caller
+
+                //  @ProjectID        INT,
+                //  @UserID           INT,
+                //  @GroupID          INT,
+                //  @LastSyncDateTime datetimeoffset,
+                //  @LastAlbumID      INT,
+                //  @Limit            INT
+                const string STORED_PROC = "s_enc_get_Albums_added";
+
+                if (limit == 0)
+                {
+                    limit = int.MaxValue;
+                }
+
+                var result = new List<PhotoAlbumForMobile>();
+
+                using (var command = portfolioDB.CreateCommand(STORED_PROC))
+                {
+                    command.Parameters["@ProjectID"].Value = portfolioDB.ProjectID;
+                    command.Parameters["@UserID"].Value = portfolioDB.RequestedByID;
+                    command.Parameters["@GroupID"].Value = portfolioDB.RequestedByGroupID;
+                    command.Parameters["@LastSyncDateTime"].Value = lastModified;
+                    command.Parameters["@LastAlbumID"].Value = lastAlbumId;
+                    command.Parameters["@Limit"].Value = limit;
+
+                    using (var reader = portfolioDB.ExecuteReader(command))
+                    {
+                        var albumIdColumn = reader.GetOrdinal("AlbumID");
+                        var nameColumn = reader.GetOrdinal("Name");
+                        var parentIdColumn = reader.GetOrdinal("ParentID");
+                        var lastModifiedColumn = reader.GetOrdinal("LastModified");
+
+                        while (reader.Read())
+                        {
+                            var album = new PhotoAlbumForMobile
+                            {
+                                AlbumID = reader.GetInt32(albumIdColumn),
+                                Name = reader.GetString(nameColumn),
+                                ParentID = reader.IsDBNull(parentIdColumn) ? (int?)null : reader.GetInt32(parentIdColumn),
+                                LastModified = ((SqlDataReader)reader).GetDateTimeOffset(lastModifiedColumn),
+                            };
+
+                            result.Add(album);
+                        }
+                    }
+                }
+
+                return result;
+            }
+        }
+
