+        /// <summary>
+        /// Returns <c>PhotoID</c> and <c>UploadedByUserID</c> for all photos in a project,
+        /// paged via OFFSET/FETCH NEXT.  Used by the mobile one-time sync to backfill
+        /// uploader identity on existing device records without re-downloading thumbnails.
+        /// </summary>
+        /// <param name="projectId">Target project ID.</param>
+        /// <param name="requestedBy">Authenticated caller context.</param>
+        /// <param name="offset">Number of rows to skip.</param>
+        /// <param name="limit">Maximum number of rows to return.</param>
+        /// <param name="error">Populated when the user lacks DMS access.</param>
+        /// <returns>A list of <see cref="PhotoUploaderIdentity"/>, or <c>null</c> if access is denied.</returns>
+        public List<PhotoUploaderIdentity> GetPhotoUploaderIdentities(int projectId, IRequestedBy requestedBy, int offset, int limit, ErrorEncountered error)
+        {
+            // Exceptions are handled by the caller
+
+            // @ProjectID        int,
+            // @Offset           int,
+            // @Limit            int
+            const string STORED_PROC = "s_enc_get_Photo_UploaderIdentity";
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, projectId))
+            {
+                if (!requestedBy.User.CanAccessDMS())
+                {
+                    error.Message = portfolioDB.GetNomenclatureProvider().GetWebSpecificError(
+                        nameof(NomenclatureMaster.FileLibraryErrorNomenclatureKeys.AccessDenied),
+                        NomenclatureMaster.WebApplicationSubAreas.DMSFileLibrary);
+                    return null;
+                }
+
+                var result = new List<PhotoUploaderIdentity>();
+
+                using (var command = portfolioDB.CreateCommand(STORED_PROC))
+                {
+                    command.Parameters["@ProjectID"].Value = portfolioDB.ProjectID;
+                    command.Parameters["@Offset"].Value = offset;
+                    command.Parameters["@Limit"].Value = limit;
+
+                    using (var reader = portfolioDB.ExecuteReader(command))
+                    {
+                        while (reader.Read())
+                        {
+                            var item = new PhotoUploaderIdentity()
+                            {
+                                PhotoID = reader.GetInt32(0),
+                                UploadedByUserID = reader.IsDBNull(1) ? (Guid?)null : reader.GetGuid(1)
+                            };
+
+                            result.Add(item);
+                        }
+                    }
+                }
+
+                return result;
+            }
+        }
+
