+ALTER PROCEDURE dbo.s_enc_propagate_PhotoAlbumSecurity
+  @AlbumID                       int ,
+  @DefaultAccessType             int ,
+  @WhenRequested                 datetimeoffset ,
+  @RequestedByUserID             uniqueidentifier
+AS
+  SET NOCOUNT ON;
+  SET XACT_ABORT ON;
+
+  Declare @ChildAlbums table (PhotoAlbumID int);
+
+   /* Find all child album IDs */
+  WITH ChildAlbums AS (
+    SELECT PhotoAlbumID
+      FROM PhotoAlbums
+     WHERE ParentID = @AlbumID
+       AND Deleted=0
+     UNION ALL
+    SELECT pa.PhotoAlbumID
+      FROM PhotoAlbums pa
+           JOIN ChildAlbums ca ON pa.ParentID = ca.PhotoAlbumID
+     WHERE pa.Deleted=0
+  )
+  INSERT
+    INTO @ChildAlbums
+  SELECT PhotoAlbumID
+    FROM ChildAlbums
+
+   /* Security records for all child albums will be overwritten by the source, so delete them all in the child albums now */
+  BEGIN TRAN
+
+  DELETE PhotoAlbumSecurity
+   WHERE AlbumID IN (SELECT PhotoAlbumID FROM @ChildAlbums)
+
+   /* Propagate the security items to the child albums */
+  INSERT
+    INTO PhotoAlbumSecurity (
+         AlbumID,
+         UserID,
+         GroupID,
+         AccessType,
+         WhenCreated,
+         CreatedByUserID,
+         LastModified,
+         LastModifiedByUserID)
+  SELECT ca.PhotoAlbumID,
+         pa.UserID,
+         pa.GroupID,
+         pa.AccessType,
+         @WhenRequested,
+         @RequestedByUserID,
+         @WhenRequested,
+         @RequestedByUserID
+    FROM PhotoAlbumSecurity pa,
+         @ChildAlbums ca
+   WHERE pa.AlbumID = @AlbumID
+
+   /* Propagate the permission settings to the child albums */
+  UPDATE PhotoAlbums
+     SET DefaultAccessType    = @DefaultAccessType,
+         AlbumManagerUserID   = @RequestedByUserID,
+         LastModified         = @WhenRequested ,
+         LastModifiedByUserID = @RequestedByUserID
+   WHERE PhotoAlbumID IN (SELECT PhotoAlbumID FROM @ChildAlbums)
+
+  COMMIT
+GO
+ALTER PROCEDURE dbo.s_enc_update_PhotoAlbumSecurity_if_users_deleted
+  @PhotoAlbumID              INT,
+  @RequestedByUserID         UNIQUEIDENTIFIER,
+  @WhenRequested             DATETIMEOFFSET
+AS
+   /* Clean up any security records with deleted users for the album */
+  DELETE s
+    FROM PhotoAlbumSecurity s
+         INNER JOIN Users u ON s.UserID=u.ID
+   WHERE s.UserID IS NOT NULL
+     AND u.Deleted = 1
+     AND s.AlbumID = @PhotoAlbumID
+
+   /* Fix data if a user was deleted and they were the owner of an album - promote portfolio admin to album owner */
+  IF EXISTS(SELECT 1
+              FROM PhotoAlbums a
+                   INNER JOIN Users u ON u.UserID = a.AlbumManagerUserID
+             WHERE a.PhotoAlbumID = @PhotoAlbumID
+               AND u.Deleted = 1)
+    BEGIN
+      DECLARE
+        @UserID INT ,
+        @GroupID INT ,
+        @UserGUID UNIQUEIDENTIFIER
+
+       /* Get the top portfolio admin that isn't deleted - should have at least one */
+      SELECT TOP 1
+             @UserID = u.ID,
+             @UserGUID = UserID,
+             @GroupID = u.GroupID
+        FROM Users u
+             INNER JOIN UserGroups ug ON u.GroupID = ug.ID
+       WHERE ug.Type = 2
+         AND u.Deleted = 0
+
+      BEGIN TRAN
+       /* Update the album manager with the new user */
+      UPDATE PhotoAlbums
+         SET AlbumManagerUserID = @UserGUID
+       WHERE PhotoAlbumID = @PhotoAlbumID
+
+       /* Make sure portfolio admin has security record with manager permission */
+      IF NOT EXISTS(SELECT 1 FROM PhotoAlbumSecurity WHERE AlbumID = @PhotoAlbumID AND UserID = @UserID)
+        BEGIN
+          INSERT
+            INTO PhotoAlbumSecurity
+               ( AlbumID,
+                 UserID,
+                 GroupID,
+                 AccessType,
+                 WhenCreated,
+                 CreatedByUserID,
+                 LastModified,
+                 LastModifiedByUserID
+               )
+          SELECT @PhotoAlbumID,
+                 @UserID,
+                 @GroupID,
+                 2047,
+                 @WhenRequested ,
+                 @RequestedByUserID ,
+                 @WhenRequested,
+                 @RequestedByUserID
+        END
+      ELSE
+        BEGIN
+          UPDATE PhotoAlbumSecurity
+             SET AccessType           = 2047 ,
+                 LastModified         = @WhenRequested,
+                 LastModifiedByUserID = @RequestedByUserID
+           WHERE AlbumID = @PhotoAlbumID
+             AND UserID = @UserID
+        END
+      COMMIT TRAN
+    END
+
+  /* Bump LastModified on the album so the mobile syncer detects this album's security changed */
+  UPDATE PhotoAlbums
+     SET LastModified         = @WhenRequested ,
+         LastModifiedByUserID = @RequestedByUserID
+   WHERE PhotoAlbumID = @PhotoAlbumID
+GO
+IF object_id('s_enc_get_Albums_added') IS NOT NULL
+BEGIN
+  DROP PROCEDURE s_enc_get_Albums_added
+END
+GO
+CREATE PROCEDURE s_enc_get_Albums_added
+  @ProjectID        INT,
+  @UserID           INT,
+  @GroupID          INT,
+  @LastSyncDateTime datetimeoffset,
+  @LastAlbumID      INT,
+  @Limit            INT
+AS
+  /* Identify candidate albums scoped to this project and cursor position first,
+     so the security aggregation below never touches albums outside this window. */
+  WITH candidates AS (
+    SELECT a.PhotoAlbumID,
+           a.AlbumName,
+           a.ParentID,
+           a.LastModified,
+           a.DefaultAccessType
+      FROM PhotoAlbums a
+     WHERE a.ProjectID = @ProjectID
+       AND a.Deleted = 0
+       AND (   a.LastModified > @LastSyncDateTime
+            OR (a.LastModified = @LastSyncDateTime AND a.PhotoAlbumID > @LastAlbumID))
+  ),
+  /* Aggregate security rows in a single pass over PhotoAlbumSecurity, joined to the candidate set.
+     A user-level AccessType = 0 (NoAccess) correctly vetoes any group grant
+     because COALESCE returns 0 before falling through to the group column. */
+  sec AS (
+    SELECT pas.AlbumID,
+           MAX(CASE WHEN pas.UserID = @UserID  AND pas.GroupID IS NULL THEN pas.AccessType END) AS UserAccessType,
+           MAX(CASE WHEN pas.UserID IS NULL AND pas.GroupID = @GroupID THEN pas.AccessType END) AS GroupAccessType
+      FROM PhotoAlbumSecurity pas
+      JOIN candidates c ON c.PhotoAlbumID = pas.AlbumID
+     WHERE (pas.UserID = @UserID  AND pas.GroupID IS NULL)
+        OR (pas.UserID IS NULL AND pas.GroupID = @GroupID)
+     GROUP BY pas.AlbumID
+  )
+  SELECT c.PhotoAlbumID AS AlbumID,
+         c.AlbumName    AS Name,
+         c.ParentID,
+         c.LastModified
+    FROM candidates c
+    LEFT JOIN sec ON sec.AlbumID = c.PhotoAlbumID
+   WHERE COALESCE(sec.UserAccessType, sec.GroupAccessType, c.DefaultAccessType) > 0
+   ORDER BY c.LastModified, c.PhotoAlbumID
+  OFFSET 0 ROWS
+   FETCH NEXT @Limit ROWS ONLY
+GO
+IF object_id('s_enc_get_Albums_removed') IS NOT NULL
+BEGIN
+  DROP PROCEDURE s_enc_get_Albums_removed
+END
+GO
+CREATE PROCEDURE s_enc_get_Albums_removed
+  @ProjectID        INT,
+  @UserID           INT,
+  @GroupID          INT,
+  @LastSyncDateTime datetimeoffset,
+  @LastAlbumID      INT,
+  @Limit            INT
+AS
+  /* Identify candidate albums scoped to this project and cursor position first,
+     so the security aggregation below never touches albums outside this window. */
+  WITH candidates AS (
+    SELECT a.PhotoAlbumID,
+           a.LastModified,
+           a.Deleted,
+           a.DefaultAccessType
+      FROM PhotoAlbums a
+     WHERE a.ProjectID = @ProjectID
+       AND (   a.LastModified > @LastSyncDateTime
+            OR (a.LastModified = @LastSyncDateTime AND a.PhotoAlbumID > @LastAlbumID))
+  ),
+  /* Aggregate security rows for the candidate set - same logic as s_enc_get_Albums_added. */
+  sec AS (
+    SELECT pas.AlbumID,
+           MAX(CASE WHEN pas.UserID = @UserID  AND pas.GroupID IS NULL THEN pas.AccessType END) AS UserAccessType,
+           MAX(CASE WHEN pas.UserID IS NULL AND pas.GroupID = @GroupID THEN pas.AccessType END) AS GroupAccessType
+      FROM PhotoAlbumSecurity pas
+      JOIN candidates c ON c.PhotoAlbumID = pas.AlbumID
+     WHERE (pas.UserID = @UserID  AND pas.GroupID IS NULL)
+        OR (pas.UserID IS NULL AND pas.GroupID = @GroupID)
+     GROUP BY pas.AlbumID
+  )
+  SELECT c.PhotoAlbumID AS AlbumID,
+         c.LastModified
+    FROM candidates c
+    LEFT JOIN sec ON sec.AlbumID = c.PhotoAlbumID
+   WHERE c.Deleted = 1
+      OR COALESCE(sec.UserAccessType, sec.GroupAccessType, c.DefaultAccessType) <= 0
+   ORDER BY c.LastModified, c.PhotoAlbumID
+  OFFSET 0 ROWS
+   FETCH NEXT @Limit ROWS ONLY
+GO
